window.jspdf = {
  jsPDF: class {
    constructor(){ this.images = []; }
    addImage(img){ this.images.push(img); }
    save(name){
      const href = this.images[0] || 'data:application/pdf;base64,';
      const a = document.createElement('a');
      a.href = href;
      a.download = name || 'export.pdf';
      document.body.appendChild(a);
      a.click();
      a.remove();
    }
  }
};
